1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  items: Item[];
14	}
15	
16	export interface QuoteResult {
17	  premium: number;
18	}
19	
20	const BASE_PREMIUMS: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	};
27	const PROCESSING_FEE = 5;
28	
29	// First-insurance surcharge of +10%, expressed as a numerator/denominator pair
30	// so the maths stays in integers: `base * 110 / 100` avoids the float error of
31	// `base * 1.1` (e.g. 100 * 1.1 === 100.00000000000001).
32	const FIRST_INSURANCE_SURCHARGE_NUMERATOR = 110;
33	const FIRST_INSURANCE_SURCHARGE_DENOMINATOR = 100;
34	
35	const sumBasePremiums = (items: Item[]): number =>
36	  items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
37	
38	export const quote = (
39	  _customer: Customer,
40	  step: QuoteStep,
41	  _quoteIndex: number,
42	): QuoteResult => {
43	  const basePremium = sumBasePremiums(step.items);
44	  const withFirstInsurance =
45	    (basePremium * FIRST_INSURANCE_SURCHARGE_NUMERATOR) /
46	    FIRST_INSURANCE_SURCHARGE_DENOMINATOR;
47	  const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
48	  return { premium };
49	};
